	MainXPBarBackground:SetPoint("BOTTOM", "MainMenuBar", "BOTTOM", -237, -10)

	MainActionBars_ApplyMicroButtonLayout()

	ChatFrame:ClearAllPoints()
	ChatFrame:SetPoint("BOTTOMLEFT", "UIParent", "BOTTOMLEFT", 32, 94)
	CombatLog:ClearAllPoints()
	CombatLog:SetPoint("BOTTOMRIGHT", "UIParent", "BOTTOMRIGHT", -32, 94)
	MainActionBars.alternativeApplied = true
end

local function MainActionBars_RestoreAlternativeLayout()
	local index

	for index = 0, 3 do
		MainActionBars_RestoreTextureState("MainMenuBarTexture" .. index, getglobal("MainMenuBarTexture" .. index))
	end

	MainActionBarArt:Hide()
	MainXPBarBackground:Hide()
	MainMenuBar:EnableMouse(1)

	MainActionBars_RestoreWidgetState("MainMenuBar", MainMenuBar)
	MainActionBars_RestoreWidgetState("ActionButton1", ActionButton1)
	MainActionBars_RestoreTextureState("SlidingActionBarTexture0", SlidingActionBarTexture0)
	MainActionBars_RestoreWidgetState("PetActionButton1", PetActionButton1)
	MainActionBars_RestoreTextureState("ShapeshiftBarLeft", ShapeshiftBarLeft)
	MainActionBars_RestoreWidgetState("ShapeshiftButton1", ShapeshiftButton1)
	MainActionBars_RestoreTextureState("MainMenuBarLeftEndCap", MainMenuBarLeftEndCap)
	MainActionBars_RestoreTextureState("MainMenuBarRightEndCap", MainMenuBarRightEndCap)
	MainActionBars_RestoreWidgetState("ActionBarUpButton", ActionBarUpButton)
	MainActionBars_RestoreWidgetState("ActionBarDownButton", ActionBarDownButton)
	MainActionBars_RestoreWidgetState("MainMenuExpBar", MainMenuExpBar)
	MainActionBars_RestoreWidgetState("ChatFrame", ChatFrame)
	MainActionBars_RestoreWidgetState("CombatLog", CombatLog)
	MainActionBars_RestoreMicroButtons()
	MainActionBars_ApplyStockLayoutFixes()
end

local function MainActionBars_UpdateGryphonButton()
	if not MainActionBarsGryphonButton then
		return
	end

	if not MainActionBars_IsEnabled() then
		MainActionBarsGryphonButton:Hide()
		return
	end

	MainActionBarsGryphonButton:Show()
	if MainActionBars_ShouldHideGryphons() then
		MainActionBarsGryphonButton:SetAlpha(1.0)
	else
		MainActionBarsGryphonButton:SetAlpha(0.55)
	end
end

local function MainActionBars_RestoreStockLayout()
	local index
	local bagButton
	local previousThis

	MainActionBars_RestoreAlternativeLayout()

	if mainActionBarsOriginalUpdateMicroButtons then
		mainActionBarsOriginalUpdateMicroButtons()
	elseif UpdateMicroButtons then
		UpdateMicroButtons()
	end

	if mainActionBarsOriginalMainMenuExpBarUpdate then
		mainActionBarsOriginalMainMenuExpBarUpdate()
	elseif MainMenuExpBar_Update then
		MainMenuExpBar_Update()
	end

	if mainActionBarsOriginalShapeshiftBarUpdate then
		mainActionBarsOriginalShapeshiftBarUpdate()
	elseif ShapeshiftBar_Update then
		ShapeshiftBar_Update()
	end

	if mainActionBarsOriginalPaperDollItemSlotButtonUpdateLock then
		previousThis = this
		for index = 0, 3 do
			bagButton = getglobal("CharacterBag" .. index .. "Slot")
			if bagButton then
				this = bagButton
				mainActionBarsOriginalPaperDollItemSlotButtonUpdateLock()
			end
		end
		this = previousThis
	end

	MainActionBars_UpdateGryphonButton()
	if MainTalentButton_UpdateState then
		MainTalentButton_UpdateState()
	end
end

local function MainActionBars_RefreshLayout()
	if MainActionBars_UseAlternativeStyle() then
		MainActionBars_ApplyAlternativeLayout()
	else
		MainActionBars_RestoreStockLayout()
	end

	MainActionBars_UpdateGryphonButton()
end

local function MainActionBars_InstallHooks()
	if not mainActionBarsOriginalUpdateMicroButtons then
		mainActionBarsOriginalUpdateMicroButtons = UpdateMicroButtons
		function UpdateMicroButtons()
			mainActionBarsOriginalUpdateMicroButtons()
			if MainActionBars_UseAlternativeStyle() and not MainActionBars.inMicroRefresh then
				MainActionBars.inMicroRefresh = true
				MainActionBars_ApplyMicroButtonLayout()
				MainActionBars.inMicroRefresh = nil
			end
		end
	end

	if not mainActionBarsOriginalShapeshiftBarUpdate then
		mainActionBarsOriginalShapeshiftBarUpdate = ShapeshiftBar_Update
		function ShapeshiftBar_Update()
			mainActionBarsOriginalShapeshiftBarUpdate()
			if MainActionBars_UseAlternativeStyle() then
				MainActionBars.pendingLayoutRefresh = true
			end
		end
	end

	if not mainActionBarsOriginalShowPetActionBar then
		mainActionBarsOriginalShowPetActionBar = ShowPetActionBar
		function ShowPetActionBar()
			mainActionBarsOriginalShowPetActionBar()
			if MainActionBars_UseAlternativeStyle() then
				MainActionBars.pendingLayoutRefresh = true
			end
		end
	end

	if not mainActionBarsOriginalHidePetActionBar then
		mainActionBarsOriginalHidePetActionBar = HidePetActionBar
		function HidePetActionBar()
			mainActionBarsOriginalHidePetActionBar()
			if MainActionBars_UseAlternativeStyle() then
				MainActionBars.pendingLayoutRefresh = true
			end
		end
	end

	if not mainActionBarsOriginalMainMenuExpBarUpdate then
		mainActionBarsOriginalMainMenuExpBarUpdate = MainMenuExpBar_Update
		function MainMenuExpBar_Update()
			mainActionBarsOriginalMainMenuExpBarUpdate()
			if MainActionBars_UseAlternativeStyle() then
				MainMenuExpBar:SetFrameLevel(0)
				MainActionBars.pendingLayoutRefresh = true
			end
		end
	end

	if not mainActionBarsOriginalPaperDollItemSlotButtonUpdateLock then
		mainActionBarsOriginalPaperDollItemSlotButtonUpdateLock = PaperDollItemSlotButton_UpdateLock
		function PaperDollItemSlotButton_UpdateLock()
			local buttonName

			if MainActionBars_UseAlternativeStyle() and this and this.GetName then
				buttonName = this:GetName()
				if strfind(buttonName, "CharacterBag") then
					return
				end
			end

			mainActionBarsOriginalPaperDollItemSlotButtonUpdateLock()
		end
	end

	MainActionBars_ApplyTooltipHook()
end

function MainActionBars:Init()
	MainActionBars_CaptureState()
	MainActionBars_InstallHooks()
	Main.RegisterEventHandler("PLAYER_ENTERING_WORLD", "action_bars", function()
		if MainActionBars_IsEnabled() then
			MainActionBars_RefreshLayout()
		elseif MainActionBars.alternativeApplied then
			MainActionBars_RestoreStockLayout()
			MainActionBars.alternativeApplied = nil
		end
	end)
	if MainActionBarsGryphonButton then
		MainActionBarsGryphonButton:Hide()
	end
end

function MainActionBars:Enable()
	MainActionBars_RefreshLayout()
	if UpdateMicroButtons then
		UpdateMicroButtons()
	end
end

function MainActionBars:Disable()
	if MainActionBars.alternativeApplied then
		MainActionBars_RestoreStockLayout()
		MainActionBars.alternativeApplied = nil
	end
end

function MainActionBars:ApplyConfig()
	MainActionBars_RefreshLayout()
	if UpdateMicroButtons then
		UpdateMicroButtons()
	end
end

function MainActionBars:OnUILayoutChanged()
	if not MainActionBars_IsEnabled() then
		return
	end

	MainActionBars:ApplyConfig()
end

function MainActionBars:ProcessDeferredRefresh()
	if MainActionBars.pendingLayoutRefresh then
		MainActionBars.pendingLayoutRefresh = nil
		MainActionBars_RefreshLayout()
	end
end

function MainActionBarsGryphonButton_OnLoad()
	this:SetText("G")
	this:Hide()
end

function MainActionBarsGryphonButton_OnClick()
	Main.SetBoolSetting("actionbars_hide_gryphons", not MainActionBars_ShouldHideGryphons(), nil, true)
	MainActionBars_RefreshLayout()
end

function MainActionBarsGryphonButton_OnEnter()
	GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
	if MainActionBars_ShouldHideGryphons() then
		GameTooltip:SetText("Show Gryphons", 1.0, 1.0, 1.0)
	else
		GameTooltip:SetText("Hide Gryphons", 1.0, 1.0, 1.0)
	end
	GameTooltip:AddLine("Toggle Gryphons side art")
	GameTooltip:Show()
end

function MainActionBarsGryphonButton_OnLeave()
	GameTooltip:Hide()
end

Main.RegisterModule("action_bars", MainActionBars)

end
-- END ActionBars.lua

-- BEGIN Clock.lua
do
local MainClockModule = {
	name = "Clock",
	description = "Shows a movable in-game clock window.",
	options = {
		{
			type = "toggle",
			key = "clock_twenty_four_hour",
			label = "Use 24-hour time",
			managerOrder = 12,
			defaultValue = false,
		},
		{
			type = "number",
			key = "clock_offset_hours",
			label = "Clock Time Offset",
			managerOrder = 3,
			requiresModule = "clock",
			defaultValue = 0,
			step = 0.5,
			minValue = -12,
			maxValue = 12,
			integer = false,
			displayFormat = "%.1f h",
		},
	},
}

local function MainClock_GetParentMetrics()
	local width
	local height

	width = UIParent and UIParent.GetWidth and UIParent:GetWidth() or nil
	height = UIParent and UIParent.GetHeight and UIParent:GetHeight() or nil

	if not width or width <= 0 then
		width = 800
	end
	if not height or height <= 0 then
		height = 600
	end

	return width, height
end

local function MainClock_GetFormattedTime()
	local hour
	local minute
	local totalMinutes
	local offsetMinutes
	local usesTwentyFourHourTime
	local isPM

	if not GetGameTime then
		return ""
	end

	hour, minute = GetGameTime()
	offsetMinutes = floor((Main.GetNumberSetting("clock_offset_hours", 0) * 60) + 0.5)
	totalMinutes = (hour * 60) + minute + offsetMinutes

	while totalMinutes < 0 do
		totalMinutes = totalMinutes + 1440
	end
	while totalMinutes >= 1440 do
		totalMinutes = totalMinutes - 1440
	end

	hour = floor(totalMinutes / 60)
	minute = Main_Mod(totalMinutes, 60)
	usesTwentyFourHourTime = Main.GetBoolSetting("clock_twenty_four_hour", false)

	if usesTwentyFourHourTime then
		return format(TEXT(TIME_TWENTYFOURHOURS), hour, minute)
	end

	isPM = hour >= 12
	if hour > 12 then
		hour = hour - 12
	end
	if hour == 0 then
		hour = 12
	end
	if isPM then
		return format(TEXT(TIME_TWELVEHOURPM), hour, minute)
	end

	return format(TEXT(TIME_TWELVEHOURAM), hour, minute)
end

function MainClock_ApplySavedPosition()
	local width
	local height
	local xRatio
	local yRatio
	local x
	local y

	width, height = MainClock_GetParentMetrics()
	xRatio = Main.GetNumberSetting("clock_x_ratio", nil)
	yRatio = Main.GetNumberSetting("clock_y_ratio", nil)
	if xRatio ~= nil and yRatio ~= nil then
		x = floor((width * xRatio) + 0.5)
		y = floor((height * yRatio) + 0.5)
	else
		x = Main.GetNumberSetting("clock_x", nil)
		y = Main.GetNumberSetting("clock_y", nil)
		if x ~= nil and y ~= nil and width > 0 and height > 0 then
			Main.SetNumberSetting("clock_x_ratio", x / width, 1, nil)
			Main.SetNumberSetting("clock_y_ratio", y / height, 1, nil)
		end
	end

	if not x or not y then
		return
	end

	MainClockFrame:ClearAllPoints()
	MainClockFrame:SetPoint("BOTTOMLEFT", "UIParent", "BOTTOMLEFT", x, y)
end

local function MainClock_UpdateText()
	if MainClockText then
		MainClockText:SetText(MainClock_GetFormattedTime())
	end
end

function MainClock_OnLoad()
	this.updateElapsed = 0
	MainClock_UpdateText()
	MainClock_ApplySavedPosition()
end

function MainClock_OnUpdate(elapsed)
	if not Main.IsModuleEnabled("clock") then
		return
	end

	this.updateElapsed = this.updateElapsed + elapsed
	if this.updateElapsed >= 0.2 then
		MainClock_UpdateText()
		this.updateElapsed = 0
	end
end

function MainClock_OnMouseDown()
	-- Frame dragging is handled by the engine via TitleRegion
end

function MainClock_OnMouseUp()
	local centerX
	local centerY
	local frameWidth
	local frameHeight
	local left
	local bottom
	local width
	local height

	-- Compute bottom-left from center (GetLeft/GetBottom not available in 0.5.3)
	centerX, centerY = this:GetCenter()
	if not centerX or not centerY then
		return
	end

	frameWidth = this:GetWidth() or 0
	frameHeight = this:GetHeight() or 0
	left = centerX - (frameWidth / 2)
	bottom = centerY - (frameHeight / 2)

	width, height = MainClock_GetParentMetrics()
	Main.SetNumberSetting("clock_x", floor(left + 0.5), 1, nil)
	Main.SetNumberSetting("clock_x_ratio", left / width, 1, nil)
	Main.SetNumberSetting("clock_y", floor(bottom + 0.5), 1, nil)
	Main.SetNumberSetting("clock_y_ratio", bottom / height, nil, nil)
end

function MainClock_OnEnter()
	GameTooltip:SetOwner(this, "ANCHOR_BOTTOMLEFT")
	GameTooltip:SetText("Game Time", 1.0, 1.0, 1.0)
	GameTooltip:AddLine(MainClock_GetFormattedTime())
	GameTooltip:Show()
end

function MainClockModule:Init()
	MainClockFrame:Hide()
end

function MainClockModule:Enable()
	MainClock_ApplySavedPosition()
	MainClock_UpdateText()
	MainClockFrame:Show()
end

function MainClockModule:Disable()
	MainClockFrame:Hide()
	if GameTooltip:IsOwned(MainClockTextButton) then
		GameTooltip:Hide()
	end
end

function MainClockModule:ApplyConfig()
	MainClock_UpdateText()
end

function MainClockModule:OnUILayoutChanged()
	if not Main.IsModuleEnabled("clock") then
		return
	end

	MainClock_ApplySavedPosition()
end

Main.RegisterModule("clock", MainClockModule)

end
-- END Clock.lua

-- BEGIN AlwaysTrack.lua
do
local MainAlwaysTrack = {
	name = "Always Track",
	description = "Keeps Find Minerals, Find Herbs, and Find Treasure active when learned.",
}

local mainAlwaysTrackBookTypes = {
	BOOKTYPE_ABILITY or "ability",
	BOOKTYPE_SPELL or "spell",
}

local mainAlwaysTrackTrackedSpells = {
	{ label = "Find Herbs", spellName = "Find Herbs", spellId = 2383 },
	{ label = "Find Minerals", spellName = "Find Minerals", spellId = 2580 },
	{ label = "Find Treasure", spellName = "Find Treasure", spellId = 2481 },
}

local mainAlwaysTrackKnownSpells = {}
local mainAlwaysTrackHasKnownSpell = nil
local mainAlwaysTrackRetryAt = nil
local MAIN_ALWAYS_TRACK_RETRY_BUFFER_SECONDS = 0.2

local function MainAlwaysTrack_IsPlayerDead()
	if UnitIsDead and UnitIsDead("player") then
		return 1
	end

	if UnitHealth and UnitHealth("player") == 0 then
		return 1
	end

	return nil
end

local function MainAlwaysTrack_FindSpellByName(spellName)
	local bookIndex
	local bookType
	local slot
	local slotName
	local emptyCount
	local maxSpells

	if not spellName or not GetSpellName then
		return nil, nil, nil
	end

	maxSpells = MAX_SPELLS or 1024
	for bookIndex = 1, Main_ArrayCount(mainAlwaysTrackBookTypes) do
		bookType = mainAlwaysTrackBookTypes[bookIndex]
		emptyCount = 0
		for slot = 1, maxSpells do
			slotName = GetSpellName(slot, bookType)
			if slotName and slotName ~= "" then
				emptyCount = 0
				if slotName == spellName then
					return slot, bookType, GetSpellTexture and GetSpellTexture(slot, bookType) or nil
				end
			else
				emptyCount = emptyCount + 1
				if emptyCount >= 64 then
					break
				end
			end
		end
	end

	return nil, nil, nil
end

local function MainAlwaysTrack_RefreshKnownSpells()
	local spellIndex
	local spellInfo
	local slot
	local bookType
	local texture
	local hadKnownSpell
	local hasKnownSpell

	hadKnownSpell = mainAlwaysTrackHasKnownSpell and 1 or nil
	mainAlwaysTrackKnownSpells = {}
	hasKnownSpell = nil

	for spellIndex = 1, Main_ArrayCount(mainAlwaysTrackTrackedSpells) do
		spellInfo = mainAlwaysTrackTrackedSpells[spellIndex]
		slot, bookType, texture = MainAlwaysTrack_FindSpellByName(spellInfo.spellName)
		if slot and bookType then
			Main_ArrayInsert(mainAlwaysTrackKnownSpells, {
				label = spellInfo.label,
				spellId = spellInfo.spellId,
				slot = slot,
				bookType = bookType,
				texture = texture,
			})
			hasKnownSpell = 1
		end
	end

	mainAlwaysTrackHasKnownSpell = hasKnownSpell

	if hadKnownSpell ~= (mainAlwaysTrackHasKnownSpell and 1 or nil) and Main.ScheduleManagerRefresh then
		Main.ScheduleManagerRefresh()
	end
end

local function MainAlwaysTrack_GetActiveBuffTextures()
	local buffIndex
	local activeBuffIndex
	local buffTexture
	local activeTextures

	activeTextures = {}
	if not GetPlayerBuff or not GetPlayerBuffTexture then
		return activeTextures
	end

	for buffIndex = 0, 15 do
		activeBuffIndex = GetPlayerBuff(buffIndex, "HELPFUL")
		if activeBuffIndex and activeBuffIndex >= 0 then
			buffTexture = GetPlayerBuffTexture(activeBuffIndex)
			if buffTexture then
				activeTextures[buffTexture] = 1
			end
		end
	end

	return activeTextures
end

local function MainAlwaysTrack_GetMissingKnownSpells()
	local activeBuffTextures
	local missingSpells
	local spellIndex
	local knownSpell

	activeBuffTextures = MainAlwaysTrack_GetActiveBuffTextures()
	missingSpells = {}

	for spellIndex = 1, Main_ArrayCount(mainAlwaysTrackKnownSpells) do
		knownSpell = mainAlwaysTrackKnownSpells[spellIndex]
		if knownSpell and knownSpell.slot and knownSpell.bookType then
			if not knownSpell.texture or not activeBuffTextures[knownSpell.texture] then
				Main_ArrayInsert(missingSpells, knownSpell)
			end
		end
	end

	return missingSpells
end

local function MainAlwaysTrack_ShouldMaintainTracking()
	if not Main.IsModuleEnabled("always_track") then
		mainAlwaysTrackRetryAt = nil
		return nil
	end

	if MainAlwaysTrack_IsPlayerDead() then
		mainAlwaysTrackRetryAt = nil
		return nil
	end

	if not mainAlwaysTrackHasKnownSpell then
		mainAlwaysTrackRetryAt = nil
		return nil
	end

	return 1
end

local function MainAlwaysTrack_GetReadyAt(knownSpell)
	local startTime
	local duration
	local enabled
	local now

	if not knownSpell or not knownSpell.slot or not knownSpell.bookType or not GetSpellCooldown then
		return 0
	end

	startTime, duration, enabled = GetSpellCooldown(knownSpell.slot, knownSpell.bookType)
	startTime = Main_ToNumber(startTime, 0) or 0
	duration = Main_ToNumber(duration, 0) or 0
	enabled = Main_ToNumber(enabled, 1)
	now = GetTime and GetTime() or 0

	if enabled == 0 then
		return now + 86400
	end

	if duration <= 0 then
		return 0
	end

	return startTime + duration + MAIN_ALWAYS_TRACK_RETRY_BUFFER_SECONDS
end

local function MainAlwaysTrack_EnsureTracking()
	local now
	local missingSpells
	local spellIndex
	local knownSpell
	local readyAt
	local nextReadyAt
	local spellToCast

	if not MainAlwaysTrack_ShouldMaintainTracking() then
		return
	end

	missingSpells = MainAlwaysTrack_GetMissingKnownSpells()
	if Main_ArrayCount(missingSpells) <= 0 then
		mainAlwaysTrackRetryAt = nil
		return
	end

	now = GetTime and GetTime() or 0

	for spellIndex = 1, Main_ArrayCount(missingSpells) do
		knownSpell = missingSpells[spellIndex]
		readyAt = MainAlwaysTrack_GetReadyAt(knownSpell)
		if not readyAt or readyAt <= now then
			spellToCast = knownSpell
			break
		end
		if not nextReadyAt or readyAt < nextReadyAt then
			nextReadyAt = readyAt
		end
	end

	if spellToCast then
		mainAlwaysTrackRetryAt = now + MAIN_ALWAYS_TRACK_RETRY_BUFFER_SECONDS
		CastSpell(spellToCast.slot, spellToCast.bookType)
		return
	end

	mainAlwaysTrackRetryAt = nextReadyAt
end

local function MainAlwaysTrack_OnWorldOrAuraChanged()
	MainAlwaysTrack_EnsureTracking()
end

local function MainAlwaysTrack_OnSpellsChanged()
	MainAlwaysTrack_RefreshKnownSpells()
	MainAlwaysTrack_EnsureTracking()
end

function MainAlwaysTrack:IsAvailable()
	return mainAlwaysTrackHasKnownSpell and true or false
end

function MainAlwaysTrack:Init()
	MainAlwaysTrack_RefreshKnownSpells()
	Main.RegisterEventHandler("PLAYER_ENTERING_WORLD", "always_track_entering_world", MainAlwaysTrack_OnWorldOrAuraChanged)
	Main.RegisterEventHandler("PLAYER_AURAS_CHANGED", "always_track_auras_changed", MainAlwaysTrack_OnWorldOrAuraChanged)
	Main.RegisterEventHandler("SPELLS_CHANGED", "always_track_spells_changed", MainAlwaysTrack_OnSpellsChanged)
end

function MainAlwaysTrack:Enable()
	MainAlwaysTrack_RefreshKnownSpells()
	MainAlwaysTrack_EnsureTracking()
end

function MainAlwaysTrack:Disable()
	mainAlwaysTrackRetryAt = nil
end

function MainAlwaysTrack:ApplyConfig()
	MainAlwaysTrack_RefreshKnownSpells()
	MainAlwaysTrack_EnsureTracking()
end

function MainAlwaysTrack:ProcessDeferredRefresh()
	local now

	if not mainAlwaysTrackRetryAt then
		return
	end

	now = GetTime and GetTime() or 0
	if now < mainAlwaysTrackRetryAt then
		return
	end

	mainAlwaysTrackRetryAt = nil
	MainAlwaysTrack_EnsureTracking()
end

Main.RegisterModule("always_track", MainAlwaysTrack)

end
-- END AlwaysTrack.lua

-- BEGIN MergedBags.lua
do
local MainMergedBags = {
	name = "Bagnon",
	description = "Replaces the stock inventory bags with one merged frame.",
}

local MAIN_MERGED_BAGS_ID = "merged_bags"
local MAIN_MERGED_BAGS_FRAME_NAME = "MainMergedBagsFrame"
local MAIN_MERGED_BAGS_BAG_IDS = { 0, 1, 2, 3, 4 }
local MAIN_MERGED_BAGS_COLUMNS = 8
local MAIN_MERGED_BAGS_ITEM_SIZE = 37
local MAIN_MERGED_BAGS_ITEM_SPACING = 3
local MAIN_MERGED_BAGS_SIDE_PADDING = 10
local MAIN_MERGED_BAGS_TOP_PADDING = 30
local MAIN_MERGED_BAGS_BOTTOM_PADDING = 12
local MAIN_MERGED_BAGS_MIN_WIDTH = 190
local MAIN_MERGED_BAGS_MIN_HEIGHT = 82
local MAIN_MERGED_BAGS_MAX_BAG_SLOTS = MAX_CONTAINER_ITEMS or 20

local mainMergedBagsVisibleCount = 0
local mainMergedBagsManualOpen = nil
local mainMergedBagsOriginals = {}
local mainMergedBagsOverridesInstalled = nil

local function MainMergedBags_GetFrame()
	return getglobal(MAIN_MERGED_BAGS_FRAME_NAME)
end

local function MainMergedBags_IsEnabled()
	return Main.IsModuleEnabled and Main.IsModuleEnabled(MAIN_MERGED_BAGS_ID) and true or false
end

local function MainMergedBags_IsControlledBag(bagId)
	bagId = Main_ToNumber(bagId, -999)
	return bagId >= 0 and bagId <= 4
end

local function MainMergedBags_CanOpen()
	local frame

	frame = MainMergedBags_GetFrame()
	if CanOpenPanels and not CanOpenPanels() and not (frame and frame:IsVisible()) then
		return nil
	end

	return 1
end

local function MainMergedBags_RegisterSpecialFrame(frameName)
	local index

	if not UISpecialFrames or not frameName then
		return
	end

	for index = 1, Main_ArrayCount(UISpecialFrames) do
		if UISpecialFrames[index] == frameName then
			return
		end
	end

	Main_ArrayInsert(UISpecialFrames, frameName)
end

local function MainMergedBags_GetBagFrame(bagId)
	return getglobal(MAIN_MERGED_BAGS_FRAME_NAME .. "Bag" .. bagId)
end

local function MainMergedBags_GetButton(bagId, slotId)
	return getglobal(MAIN_MERGED_BAGS_FRAME_NAME .. "Bag" .. bagId .. "Item" .. slotId)
end

local function MainMergedBags_CloseStockFrames()
	local index
	local frame
	local maxFrames

	maxFrames = NUM_CONTAINER_FRAMES or 16
	for index = 1, maxFrames do
		frame = getglobal("ContainerFrame" .. index)
		if frame and frame:IsVisible() then
			frame:Hide()
		end
	end
end

local function MainMergedBags_UpdateBagButtonChecks(isShown)
	local index
	local bagButton

	if MainMenuBarBackpackButton and MainMenuBarBackpackButton.SetChecked then
		MainMenuBarBackpackButton:SetChecked(isShown and 1 or 0)
	end

	for index = 0, 3 do
		bagButton = getglobal("CharacterBag" .. index .. "Slot")
		if bagButton and bagButton.SetChecked then
			if isShown and GetContainerNumSlots and GetContainerNumSlots(index + 1) > 0 then
				bagButton:SetChecked(1)
			else
				bagButton:SetChecked(0)
			end
		end
	end
end

local function MainMergedBags_UpdateItem(button)
	local bagId
	local slotId
	local texture
	local itemCount
	local locked
	local cooldown

	if not button then
		return
	end

	bagId = button:GetParent() and button:GetParent():GetID() or nil
	slotId = button:GetID()
	if bagId == nil or not slotId or not GetContainerItemInfo then
		return
	end

	texture, itemCount, locked = GetContainerItemInfo(bagId, slotId)
	SetItemButtonTexture(button, texture)
	SetItemButtonCount(button, itemCount)

	if locked then
		SetItemButtonTextureVertexColor(button, 0.5, 0.5, 0.5)
	else
		SetItemButtonTextureVertexColor(button, 1.0, 1.0, 1.0)
	end

	if texture then
		if ContainerFrame_UpdateCooldown then
			ContainerFrame_UpdateCooldown(bagId, button)
		end
	else
		cooldown = getglobal(button:GetName() .. "Cooldown")
		if cooldown then
			cooldown:Hide()
		end
	end

	if SetItemButtonNormalTextureVertexColor then
		SetItemButtonNormalTextureVertexColor(button, 1, 1, 1)
	end
end

local function MainMergedBags_UpdateVisibleItems()
	local bagIndex
	local bagId
	local slotId
	local button

	for bagIndex = 1, Main_ArrayCount(MAIN_MERGED_BAGS_BAG_IDS) do
		bagId = MAIN_MERGED_BAGS_BAG_IDS[bagIndex]
		for slotId = 1, MAIN_MERGED_BAGS_MAX_BAG_SLOTS do
			button = MainMergedBags_GetButton(bagId, slotId)
			if button and button:IsShown() then
				MainMergedBags_UpdateItem(button)
			end
		end
	end
end

local function MainMergedBags_UpdateLayout()
	local frame
	local rows
	local usedColumns
	local width
	local height

	frame = MainMergedBags_GetFrame()
	if not frame then
		return
	end

	if mainMergedBagsVisibleCount > 0 then
		rows = ceil(mainMergedBagsVisibleCount / MAIN_MERGED_BAGS_COLUMNS)
		if mainMergedBagsVisibleCount < MAIN_MERGED_BAGS_COLUMNS then
			usedColumns = mainMergedBagsVisibleCount
		else
			usedColumns = MAIN_MERGED_BAGS_COLUMNS
		end
		width = (usedColumns * MAIN_MERGED_BAGS_ITEM_SIZE) + ((usedColumns - 1) * MAIN_MERGED_BAGS_ITEM_SPACING) + (MAIN_MERGED_BAGS_SIDE_PADDING * 2)
		height = (rows * MAIN_MERGED_BAGS_ITEM_SIZE) + ((rows - 1) * MAIN_MERGED_BAGS_ITEM_SPACING) + MAIN_MERGED_BAGS_TOP_PADDING + MAIN_MERGED_BAGS_BOTTOM_PADDING
	else
		width = MAIN_MERGED_BAGS_MIN_WIDTH
		height = MAIN_MERGED_BAGS_MIN_HEIGHT
	end

	if width < MAIN_MERGED_BAGS_MIN_WIDTH then
		width = MAIN_MERGED_BAGS_MIN_WIDTH
	end
	if height < MAIN_MERGED_BAGS_MIN_HEIGHT then
		height = MAIN_MERGED_BAGS_MIN_HEIGHT
	end

	frame:SetWidth(width)
	frame:SetHeight(height)
end

local function MainMergedBags_Generate()
	local frame
	local bagIndex
	local bagId
	local bagSize
	local slotId
	local button
	local visibleIndex
	local column
	local row

	frame = MainMergedBags_GetFrame()
	if not frame then
		return
	end

	visibleIndex = 0

	for bagIndex = 1, Main_ArrayCount(MAIN_MERGED_BAGS_BAG_IDS) do
		bagId = MAIN_MERGED_BAGS_BAG_IDS[bagIndex]
		bagSize = GetContainerNumSlots and GetContainerNumSlots(bagId) or 0
		bagSize = Main_ToNumber(bagSize, 0) or 0

		for slotId = 1, MAIN_MERGED_BAGS_MAX_BAG_SLOTS do
			button = MainMergedBags_GetButton(bagId, slotId)
			if button then
				if slotId <= bagSize then
					visibleIndex = visibleIndex + 1
					button:SetID(slotId)
					button:ClearAllPoints()
					column = Main_Mod(visibleIndex - 1, MAIN_MERGED_BAGS_COLUMNS)
					row = floor((visibleIndex - 1) / MAIN_MERGED_BAGS_COLUMNS)
						button:SetPoint(
							"TOPLEFT",
							MAIN_MERGED_BAGS_FRAME_NAME,
							"TOPLEFT",
							MAIN_MERGED_BAGS_SIDE_PADDING + (column * (MAIN_MERGED_BAGS_ITEM_SIZE + MAIN_MERGED_BAGS_ITEM_SPACING)),
							-(MAIN_MERGED_BAGS_TOP_PADDING + (row * (MAIN_MERGED_BAGS_ITEM_SIZE + MAIN_MERGED_BAGS_ITEM_SPACING)))
					)
					MainMergedBags_UpdateItem(button)
					button:Show()
				else
					button:Hide()
				end
			end
		end
	end

	mainMergedBagsVisibleCount = visibleIndex
	MainMergedBags_UpdateLayout()
end

local function MainMergedBags_Open(automatic)
	local frame

	if not MainMergedBags_CanOpen() then
		return
	end

	frame = MainMergedBags_GetFrame()
	if not frame then
		return
	end

	MainMergedBags_CloseStockFrames()
	MainMergedBags_Generate()
	frame:Show()
	if not automatic then
		mainMergedBagsManualOpen = 1
	end
end

local function MainMergedBags_Close(automatic)
	local frame

	frame = MainMergedBags_GetFrame()
	if not frame then
		mainMergedBagsManualOpen = nil
		return
	end

	if automatic and mainMergedBagsManualOpen then
		return
	end

	mainMergedBagsManualOpen = nil
	frame:Hide()
end

local function MainMergedBags_Toggle()
	local frame

	frame = MainMergedBags_GetFrame()
	if frame and frame:IsVisible() then
		MainMergedBags_Close()
	else
		MainMergedBags_Open()
	end
end

local function MainMergedBags_InstallOverrides()
	if mainMergedBagsOverridesInstalled then
		return
	end

	mainMergedBagsOriginals.ToggleBag = ToggleBag
	mainMergedBagsOriginals.ToggleBackpack = ToggleBackpack
	mainMergedBagsOriginals.OpenBag = OpenBag
	mainMergedBagsOriginals.CloseBag = CloseBag
	mainMergedBagsOriginals.IsBagOpen = IsBagOpen
	mainMergedBagsOriginals.OpenBackpack = OpenBackpack
	mainMergedBagsOriginals.CloseBackpack = CloseBackpack
	mainMergedBagsOriginals.OpenAllBags = OpenAllBags
	mainMergedBagsOriginals.CloseAllBags = CloseAllBags

	function ToggleBag(id)
		if MainMergedBags_IsEnabled() and MainMergedBags_IsControlledBag(id) then
			MainMergedBags_Toggle()
			return
		end

		if mainMergedBagsOriginals.ToggleBag then
			mainMergedBagsOriginals.ToggleBag(id)
		end
	end

	function ToggleBackpack()
		if MainMergedBags_IsEnabled() then
			MainMergedBags_Toggle()
			return
		end

		if mainMergedBagsOriginals.ToggleBackpack then
			mainMergedBagsOriginals.ToggleBackpack()
		end
	end

	function OpenBag(id)
		if MainMergedBags_IsEnabled() and MainMergedBags_IsControlledBag(id) then
			MainMergedBags_Open(1)
			return
		end

		if mainMergedBagsOriginals.OpenBag then
			mainMergedBagsOriginals.OpenBag(id)
		end
	end

	function CloseBag(id)
		if MainMergedBags_IsEnabled() and MainMergedBags_IsControlledBag(id) then
			MainMergedBags_Close(1)
			return
		end

		if mainMergedBagsOriginals.CloseBag then
			mainMergedBagsOriginals.CloseBag(id)
		end
	end

	function IsBagOpen(id)
		local frame

		if MainMergedBags_IsEnabled() and MainMergedBags_IsControlledBag(id) then
			frame = MainMergedBags_GetFrame()
			if frame and frame:IsVisible() then
				return 1
			end
			return nil
		end

		if mainMergedBagsOriginals.IsBagOpen then
			return mainMergedBagsOriginals.IsBagOpen(id)
		end

		return nil
	end

	function OpenBackpack()
		if MainMergedBags_IsEnabled() then
			MainMergedBags_Open(1)
			return
		end

		if mainMergedBagsOriginals.OpenBackpack then
			mainMergedBagsOriginals.OpenBackpack()
		end
	end

	function CloseBackpack()
		if MainMergedBags_IsEnabled() then
			MainMergedBags_Close(1)
			return
		end

		if mainMergedBagsOriginals.CloseBackpack then
			mainMergedBagsOriginals.CloseBackpack()
		end
	end

	function OpenAllBags(forceOpen)
		if MainMergedBags_IsEnabled() then
			if forceOpen then
				MainMergedBags_Open(1)
			else
				MainMergedBags_Toggle()
			end
			return
		end

		if mainMergedBagsOriginals.OpenAllBags then
			mainMergedBagsOriginals.OpenAllBags(forceOpen)
		end
	end

	function CloseAllBags()
		if MainMergedBags_IsEnabled() then
			MainMergedBags_Close()
			return
		end

		if mainMergedBagsOriginals.CloseAllBags then
			mainMergedBagsOriginals.CloseAllBags()
		end
	end

	mainMergedBagsOverridesInstalled = 1
end

local function MainMergedBags_OnEnteringWorld()
	local frame

	if not MainMergedBags_IsEnabled() then
		return
	end

	frame = MainMergedBags_GetFrame()
	MainMergedBags_CloseStockFrames()
	if frame and frame:IsVisible() then
		MainMergedBags_Generate()
	end
end

local function MainMergedBags_OnBagUpdate()
	local frame

	if not MainMergedBags_IsEnabled() then
		return
	end

	frame = MainMergedBags_GetFrame()
	if frame and frame:IsVisible() then
		MainMergedBags_Generate()
	end
end

local function MainMergedBags_OnCooldownOrLockChanged()
	local frame

	if not MainMergedBags_IsEnabled() then
		return
	end

	frame = MainMergedBags_GetFrame()
	if frame and frame:IsVisible() then
		MainMergedBags_UpdateVisibleItems()
	end
end

function MainMergedBagsFrame_OnShow()
	MainMergedBags_UpdateBagButtonChecks(1)
	if PlaySound then
		PlaySound("igBackPackOpen")
	end
end

function MainMergedBagsFrame_OnHide()
	MainMergedBags_UpdateBagButtonChecks(nil)
	if PlaySound then
		PlaySound("igBackPackClose")
	end
end

function MainMergedBagsCloseButton_OnClick()
	MainMergedBags_Close()
end

function MainMergedBags:Init()
	MainMergedBags_RegisterSpecialFrame(MAIN_MERGED_BAGS_FRAME_NAME)
	MainMergedBags_InstallOverrides()
	Main.RegisterEventHandler("PLAYER_ENTERING_WORLD", "merged_bags_entering_world", MainMergedBags_OnEnteringWorld)
	Main.RegisterEventHandler("BAG_UPDATE", "merged_bags_bag_update", MainMergedBags_OnBagUpdate)
	Main.RegisterEventHandler("BAG_UPDATE_COOLDOWN", "merged_bags_cooldown", MainMergedBags_OnCooldownOrLockChanged)
	Main.RegisterEventHandler("ITEM_LOCK_CHANGED", "merged_bags_lock", MainMergedBags_OnCooldownOrLockChanged)
end

function MainMergedBags:Enable()
	local frame

	frame = MainMergedBags_GetFrame()
	MainMergedBags_CloseStockFrames()
	if frame and frame:IsVisible() then
		MainMergedBags_Generate()
	end
end

function MainMergedBags:Disable()
	MainMergedBags_Close()
end

function MainMergedBags:ApplyConfig()
	if MainMergedBags_IsEnabled() then
		self:Enable()
	else
		self:Disable()
	end
end

Main.RegisterModule(MAIN_MERGED_BAGS_ID, MainMergedBags)

end
-- END MergedBags.lua

