do
local MainTalentButton = {
	name = "Talents Button",
	description = "Adds a talents micro button beside the main menu icons.",
	managerHidden = 1,
	options = {
		{
			type = "toggle",
			key = "actionbars_show_talent_button",
			label = "Show talents button",
			managerOrder = 10,
			defaultValue = true,
			requiresModule = false,
		},
	},
}

local MainTalentButtonOriginalUpdateMicroButtons = nil

function MainTalentButton_ShouldShow()
	return Main.IsModuleEnabled("talent_button") and Main.GetBoolSetting("actionbars_show_talent_button", true)
end

local function MainTalentButton_UpdateAnchor()
	if not MainTalentMicroButton then
		return
	end

	if Main.IsModuleEnabled("action_bars") then
		return
	end

	MainTalentMicroButton:ClearAllPoints()
	MainTalentMicroButton:SetPoint("BOTTOMLEFT", "BugsMicroButton", "BOTTOMRIGHT", -2, 0)

	if BugsMicroButton and BugsMicroButton.GetFrameLevel then
		MainTalentMicroButton:SetFrameLevel(BugsMicroButton:GetFrameLevel())
	end
end

local function MainTalentButton_UpdateTooltip()
	if MainTalentMicroButton then
		MainTalentMicroButton.tooltipText = MicroButtonTooltipText(TEXT(TALENTS_BUTTON), "TOGGLETALENTS")
	end
end

function MainTalentButton_UpdateState()
	if not MainTalentMicroButton then
		return
	end

	if not MainTalentButton_ShouldShow() then
		MainTalentMicroButton:Hide()
		return
	end

	MainTalentButton_UpdateAnchor()
	MainTalentMicroButton:Show()
	if TalentTrainerFrame and TalentTrainerFrame:IsVisible() then
		MainTalentMicroButton:SetButtonState("PUSHED", 1)
	else
		MainTalentMicroButton:SetButtonState("NORMAL")
	end
end

function MainTalentMicroButton_OnLoad()
	LoadMicroButtonTextures("Talents")
	this:RegisterEvent("UPDATE_BINDINGS")
	MainTalentButton_UpdateTooltip()
	this:Hide()
end

function MainTalentMicroButton_OnEvent(event)
	if event == "UPDATE_BINDINGS" then
		MainTalentButton_UpdateTooltip()
	end
end

function MainTalentMicroButton_OnClick()
	ToggleCharacter("TalentTrainerFrame")
	UpdateMicroButtons()
end

function MainTalentButton:Init()
	if not self.hookedUpdate then
		-- Wrap the stock updater so the extra button tracks the same refresh points as the built-in micro buttons.
		MainTalentButtonOriginalUpdateMicroButtons = UpdateMicroButtons
		function UpdateMicroButtons()
			if MainTalentButtonOriginalUpdateMicroButtons then
				MainTalentButtonOriginalUpdateMicroButtons()
			end
			MainTalentButton_UpdateState()
		end
		self.hookedUpdate = 1
	end

	MainTalentButton_UpdateState()
end

function MainTalentButton:Enable()
	MainTalentButton_UpdateState()
	if UpdateMicroButtons then
		UpdateMicroButtons()
	end
end

function MainTalentButton:Disable()
	if GameTooltip and GameTooltip:IsOwned(MainTalentMicroButton) then
		GameTooltip:Hide()
	end
	MainTalentButton_UpdateState()
	if UpdateMicroButtons then
		UpdateMicroButtons()
	end
end

function MainTalentButton:ApplyConfig()
	MainTalentButton_UpdateState()
	if UpdateMicroButtons then
		UpdateMicroButtons()
	end
end

function MainTalentButton:OnUILayoutChanged()
	MainTalentButton_UpdateState()
end

Main.RegisterModule("talent_button", MainTalentButton)

end
-- END TalentButton.lua

-- BEGIN TargetAuras.lua
do
local MainTargetAuras = {
	name = "Target Auras",
	description = "Shows tracked target aura icons from the shared addon API.",
	managerHidden = 1,
	options = {
		{
			type = "toggle",
			key = "unitframes_show_target_auras",
			label = "Show target auras",
			defaultValue = true,
			managerOrder = 4,
			requiresModule = false,
		},
		{
			type = "toggle",
			key = "target_auras_show_numbers",
			label = "Show aura timer numbers",
			defaultValue = false,
			managerOrder = 5,
			requiresModule = false,
		},
	},
}

local MAIN_TARGET_AURAS_UPDATE_RATE = 0.2
local MAIN_TARGET_AURAS_ACTIVE_REFRESH_RATE = 3
local MAIN_TARGET_AURAS_IDLE_REFRESH_RATE = 8
local MAIN_TARGET_AURAS_MAX_BUTTONS = 16
local MAIN_TARGET_AURAS_DEFAULT_ICON = "Interface\\Icons\\Temp"

local mainTargetAurasUnitGainsBuff = AURAADDEDOTHERHELPFUL and Main_StringGSub(format(AURAADDEDOTHERHELPFUL, "", ""), "%.", "") or nil
local mainTargetAurasUnitGainsDebuff = AURAADDEDOTHERHARMFUL and Main_StringGSub(format(AURAADDEDOTHERHARMFUL, "", ""), "%.", "") or nil
local mainTargetAurasUnitLosesAura = AURAREMOVEDOTHER and Main_StringGSub(format(AURAREMOVEDOTHER, "", ""), "%.", "") or nil
local mainTargetAurasUnitChangesAura = AURACHANGEDOTHER and Main_StringGSub(format(AURACHANGEDOTHER, "", "", ""), "%.", "") or nil
local mainTargetAurasPlayerGainsBuff = AURAADDEDSELFHELPFUL and Main_StringGSub(format(AURAADDEDSELFHELPFUL, ""), "%.", "") or nil
local mainTargetAurasPlayerGainsDebuff = AURAADDEDSELFHARMFUL and Main_StringGSub(format(AURAADDEDSELFHARMFUL, ""), "%.", "") or nil
local mainTargetAurasPlayerLosesAura = AURAREMOVEDSELF and Main_StringGSub(format(AURAREMOVEDSELF, ""), "%.", "") or nil
local mainTargetAurasPlayerChangesAura = AURACHANGEDSELF and Main_StringGSub(format(AURACHANGEDSELF, "", ""), "%.", "") or nil

local function MainTargetAuras_IsPlayerDead()
	return Main.API and Main.API.IsPlayerDead and Main.API:IsPlayerDead()
end

local function MainTargetAuras_GetRemainingSeconds(aura)
	local remaining

	if not aura or not aura.expiresAt then
		return nil
	end

	remaining = aura.expiresAt - (GetTime and GetTime() or 0)
	if remaining < 0 then
		return 0
	end

	return remaining
end

local function MainTargetAuras_CollectEntries()
	local source
	local entries
	local count
	local index
	local aura

	source = Main.API and Main.API.GetUnitAuras and Main.API:GetUnitAuras("target") or nil
	entries = {}
	count = 0
	if not source then
		return entries
	end

	for index = 1, Main_ArrayCount(source) do
		aura = source[index]
		if aura and (aura.remainingMs == nil or aura.remainingMs < 0 or MainTargetAuras_GetRemainingSeconds(aura) > 0) then
			count = count + 1
			entries[count] = aura
		end
	end

	Main_SortArray(entries, function(left, right)
		local leftHarmful
		local rightHarmful
		local leftExpiresAt
		local rightExpiresAt

		leftHarmful = left and left.harmful and 1 or 0
		rightHarmful = right and right.harmful and 1 or 0
		if leftHarmful ~= rightHarmful then
			return leftHarmful > rightHarmful
		end

		leftExpiresAt = left and left.expiresAt or 999999999
		rightExpiresAt = right and right.expiresAt or 999999999
		if leftExpiresAt == rightExpiresAt then
			return (left and left.name or "") < (right and right.name or "")
		end

		return leftExpiresAt < rightExpiresAt
	end)

	return entries
end

local function MainTargetAuras_GetButton(index)
	return getglobal("MainTargetAura" .. index)
end

local function MainTargetAuras_GetCountFontString(button)
	local count

	if not button or not button.GetName then
		return nil
	end

	count = getglobal(button:GetName() .. "Count")
	if count then
		return count
	end

	return getglobal(button:GetName() .. "CountFrameCount")
end

local function MainTargetAuras_GetBorder(button)
	if not button or not button.GetName then
		return nil
	end

	return getglobal(button:GetName() .. "Border")
end

local function MainTargetAuras_IsCountEnabled()
	return Main.GetBoolSetting and Main.GetBoolSetting("target_auras_show_numbers", false)
end

local function MainTargetAuras_ShouldShow()
	return Main.IsModuleEnabled("target_auras") and Main.GetBoolSetting("unitframes_show_target_auras", true)
end

local function MainTargetAuras_GetRefreshRate()
	local entries

	if not MainTargetAuras_ShouldShow() then
		return nil
	end

	entries = Main.API and Main.API.GetUnitAuras and Main.API:GetUnitAuras("target") or nil
	if entries and Main_ArrayCount(entries) > 0 then
		return MAIN_TARGET_AURAS_ACTIVE_REFRESH_RATE
	end

	return MAIN_TARGET_AURAS_IDLE_REFRESH_RATE
end

local function MainTargetAuras_FormatCountText(remainingSeconds)
	if not remainingSeconds or remainingSeconds <= 0 then
		return ""
	end

	if remainingSeconds >= 86400 then
		return ceil(remainingSeconds / 86400) .. "d"
	end
	if remainingSeconds >= 3600 then
		return ceil(remainingSeconds / 3600) .. "h"
	end
	if remainingSeconds >= 60 then
		return tostring(ceil(remainingSeconds / 60))
	end

	return tostring(ceil(remainingSeconds))
end

local function MainTargetAuras_ShowTooltip(button, resetOwner)
	local aura
	local remainingSeconds

	aura = button and button.aura or nil
	if not aura then
		return
	end

	if resetOwner then
		GameTooltip:SetOwner(button, "ANCHOR_BOTTOMLEFT")
	end
	if GameTooltip.ClearLines then
		GameTooltip:ClearLines()
	end
	GameTooltip:SetText(aura.name or "", 1.0, 1.0, 1.0)
	if aura.harmful then
		GameTooltip:AddLine("Debuff", "", 1.0, 0.2, 0.2)
	else
		GameTooltip:AddLine("Buff", "", 0.2, 0.8, 1.0)
	end
	remainingSeconds = MainTargetAuras_GetRemainingSeconds(aura)
	if remainingSeconds and remainingSeconds > 0 then
		GameTooltip:AddLine(Main_SecondsToTimeAbbrev(remainingSeconds) .. " remaining", "", 1.0, 0.82, 0.0)
	end
	GameTooltip:Show()
end

local function MainTargetAuras_ShouldResetCooldown(previousAura, aura)
	if not aura then
		return nil
	end

	if not previousAura then
		return 1
	end

	if previousAura.name ~= aura.name or previousAura.harmful ~= aura.harmful or previousAura.iconPath ~= aura.iconPath then
		return 1
	end

	if not previousAura.expiresAt or not aura.expiresAt then
		return 1
	end

	if math.abs(previousAura.expiresAt - aura.expiresAt) > 1.2 then
		return 1
	end

	return nil
end

local function MainTargetAuras_SetButton(button, aura)
	local previousAura
	local icon
	local cooldown
	local count
	local border
	local durationSeconds
	local remainingSeconds

	if not button then
		return
	end

	previousAura = button.aura
	button.aura = aura
	icon = getglobal(button:GetName() .. "Icon")
	cooldown = getglobal(button:GetName() .. "Cooldown")
	count = MainTargetAuras_GetCountFontString(button)
	border = MainTargetAuras_GetBorder(button)

	if icon then
		icon:SetTexture((aura and aura.iconPath) or MAIN_TARGET_AURAS_DEFAULT_ICON)
	end

	if aura then
		remainingSeconds = MainTargetAuras_GetRemainingSeconds(aura)
		durationSeconds = aura.remainingMs and aura.remainingMs > 0 and (aura.remainingMs / 1000) or nil
		if cooldown and remainingSeconds and remainingSeconds > 0 and MainTargetAuras_ShouldResetCooldown(previousAura, aura) then
			CooldownFrame_SetTimer(cooldown, aura.receivedAt or (GetTime and GetTime() or 0), durationSeconds or remainingSeconds, 1)
		elseif cooldown then
			if not previousAura or not aura or aura.name ~= previousAura.name then
				CooldownFrame_SetTimer(cooldown, 0, 0, 0)
			end
		end

		if border then
			if aura.harmful then
				border:Show()
			else
				border:Hide()
			end
		end

		if count then
			if MainTargetAuras_IsCountEnabled() and remainingSeconds and remainingSeconds > 0 then
				count:SetText(MainTargetAuras_FormatCountText(remainingSeconds))
				if count.SetTextColor then
					count:SetTextColor(1.0, 0.82, 0.0)
				end
				count:Show()
			else
				count:SetText("")
				count:Hide()
			end
		end

		button:Show()
	else
		if cooldown then
			CooldownFrame_SetTimer(cooldown, 0, 0, 0)
		end
		if border then
			border:Hide()
		end
		if count then
			count:SetText("")
			count:Hide()
		end
		button:Hide()
	end
end

local function MainTargetAuras_UpdateDisplay()
	local entries
	local index

	if not Main.IsModuleEnabled("target_auras") then
		MainTargetAurasFrame:Hide()
		return
	end

	if not MainTargetAuras_ShouldShow() then
		MainTargetAurasFrame:Hide()
		return
	end

	if not TargetFrame or not TargetFrame:IsVisible() or not UnitExists("target") or
		MainTargetAuras_IsPlayerDead() or
		((UnitIsDead and UnitIsDead("target")) or (UnitHealth and UnitHealth("target") == 0)) then
		MainTargetAurasFrame:Hide()
		return
	end

	entries = MainTargetAuras_CollectEntries()
	for index = 1, MAIN_TARGET_AURAS_MAX_BUTTONS do
		MainTargetAuras_SetButton(MainTargetAuras_GetButton(index), entries[index])
	end

	MainTargetAurasFrame:Show()
end

local function MainTargetAuras_RequestSnapshot(force)
	if not MainTargetAuras_ShouldShow() or not Main.API or not Main.API.RequestUnitAuras or not UnitExists or not UnitExists("target") then
		return
	end

	if MainTargetAuras_IsPlayerDead() then
		if Main.API.ResetUnitAuras then
			Main.API:ResetUnitAuras("target")
		end
		return
	end

	Main.API:RequestUnitAuras("target", force)
end

local function MainTargetAuras_ExtractTargetName(message, marker, capturePattern, targetCaptureIndex)
	local payload
	local firstValue
	local secondValue
	local thirdValue

	if not marker or not message or not Main_StringFind(message, marker) then
		return nil
	end

	payload = Main_StringGSub(message, marker, "`")
	payload = Main_StringGSub(payload, "%.$", "")
	_, _, firstValue, secondValue, thirdValue = Main_StringFind(payload, capturePattern)

	if targetCaptureIndex == 1 then
		return firstValue
	end
	if targetCaptureIndex == 2 then
		return secondValue
	end

	return thirdValue
end

local function MainTargetAuras_CombatMessageAffectsCurrentTarget(message)
	local currentTarget
	local targetName

	if not message or not UnitExists or not UnitExists("target") then
		return nil
	end

	currentTarget = UnitName and UnitName("target") or nil
	if not currentTarget or currentTarget == "" then
		return nil
	end

	targetName = MainTargetAuras_ExtractTargetName(message, mainTargetAurasUnitGainsBuff, "^(.-)`(.-)$", 1)
	if targetName == currentTarget then
		return 1
	end

	targetName = MainTargetAuras_ExtractTargetName(message, mainTargetAurasUnitGainsDebuff, "^(.-)`(.-)$", 1)
	if targetName == currentTarget then
		return 1
	end

	targetName = MainTargetAuras_ExtractTargetName(message, mainTargetAurasUnitLosesAura, "^(.-)`(.-)$", 2)
	if targetName == currentTarget then
		return 1
	end

	targetName = MainTargetAuras_ExtractTargetName(message, mainTargetAurasUnitChangesAura, "^(.-)`(.-)`(.-)$", 1)
	if targetName == currentTarget then
		return 1
	end

	return nil
end

local function MainTargetAuras_CombatMessageAffectsPlayer(message)
	if not message then
		return nil
	end

	if mainTargetAurasPlayerGainsBuff and Main_StringFind(message, mainTargetAurasPlayerGainsBuff) then
		return 1
	end
	if mainTargetAurasPlayerGainsDebuff and Main_StringFind(message, mainTargetAurasPlayerGainsDebuff) then
		return 1
	end
	if mainTargetAurasPlayerLosesAura and Main_StringFind(message, mainTargetAurasPlayerLosesAura) then
		return 1
	end
	if mainTargetAurasPlayerChangesAura and Main_StringFind(message, mainTargetAurasPlayerChangesAura) then
		return 1
	end

	return nil
end

function MainTargetAurasFrame_OnLoad()
	this.displayElapsed = 0
	this.refreshElapsed = 0
	this:RegisterEvent("PLAYER_ENTERING_WORLD")
	this:RegisterEvent("PLAYER_TARGET_CHANGED")
	this:RegisterEvent("PLAYER_DEAD")
	this:RegisterEvent("PLAYER_ALIVE")
	this:RegisterEvent("PLAYER_UNGHOST")
	this:RegisterEvent("CHAT_MSG_COMBAT_LOG_ENEMY")
	this:RegisterEvent("CHAT_MSG_COMBAT_LOG_SELF")
	this:RegisterEvent("CHAT_MSG_COMBAT_LOG_PARTY")
	this:Hide()
end

function MainTargetAurasFrame_OnEvent(event)
	if event == "PLAYER_ENTERING_WORLD" or event == "PLAYER_TARGET_CHANGED"
		or event == "PLAYER_DEAD" or event == "PLAYER_ALIVE" or event == "PLAYER_UNGHOST" then
		if Main.API and Main.API.ResetUnitAuras then
			Main.API:ResetUnitAuras("target")
		end
		this.displayElapsed = MAIN_TARGET_AURAS_UPDATE_RATE
		this.refreshElapsed = 0
		MainTargetAuras_RequestSnapshot(1)
		MainTargetAuras_UpdateDisplay()
		return
	end

	if not MainTargetAuras_ShouldShow() then
		return
	end

	if (event == "CHAT_MSG_COMBAT_LOG_ENEMY" or event == "CHAT_MSG_COMBAT_LOG_PARTY")
		and MainTargetAuras_CombatMessageAffectsCurrentTarget(arg1) then
		this.refreshElapsed = 0
		MainTargetAuras_RequestSnapshot(1)
		return
	end

	if event == "CHAT_MSG_COMBAT_LOG_SELF" and UnitIsUnit and UnitIsUnit("target", "player")
		and MainTargetAuras_CombatMessageAffectsPlayer(arg1) then
		this.refreshElapsed = 0
		MainTargetAuras_RequestSnapshot(1)
	end
end

function MainTargetAurasFrame_OnUpdate(elapsed)
	local refreshRate

	if not MainTargetAuras_ShouldShow() then
		MainTargetAurasFrame:Hide()
		return
	end

	if not UnitExists or not UnitExists("target") then
		if Main.API and Main.API.ResetUnitAuras then
			Main.API:ResetUnitAuras("target")
		end
		MainTargetAurasFrame:Hide()
		return
	end

	if MainTargetAuras_IsPlayerDead() then
		if Main.API and Main.API.ResetUnitAuras then
			Main.API:ResetUnitAuras("target")
		end
		MainTargetAurasFrame:Hide()
		return
	end

	this.displayElapsed = this.displayElapsed + elapsed
	this.refreshElapsed = this.refreshElapsed + elapsed

	refreshRate = MainTargetAuras_GetRefreshRate()
	if refreshRate and this.refreshElapsed >= refreshRate then
		this.refreshElapsed = 0
		MainTargetAuras_RequestSnapshot(nil)
	end

	if this.displayElapsed < MAIN_TARGET_AURAS_UPDATE_RATE then
		return
	end

	this.displayElapsed = 0
	MainTargetAuras_UpdateDisplay()
end

function MainTargetAuraButton_OnEnter()
	if not this or not this.aura then
		return
	end

	MainTargetAuras_ShowTooltip(this, 1)
	this.updateTooltip = nil
end

function MainTargetAuraButton_OnLeave()
	GameTooltip:Hide()
	this.updateTooltip = nil
end

function MainTargetAuraButton_OnUpdate(elapsed)
	return
end

function MainTargetAuras:Init()
	MainTargetAurasFrame:Hide()
end

function MainTargetAuras:Enable()
	if Main.API and Main.API.ResetUnitAuras then
		Main.API:ResetUnitAuras("target")
	end
	if MainTargetAurasFrame then
		MainTargetAurasFrame.refreshElapsed = 0
	end
	MainTargetAuras_RequestSnapshot(1)
	MainTargetAuras_UpdateDisplay()
end

function MainTargetAuras:ApplyConfig()
	if MainTargetAuras_ShouldShow() then
		if MainTargetAurasFrame then
			MainTargetAurasFrame.refreshElapsed = 0
		end
		MainTargetAuras_RequestSnapshot(1)
	end
	MainTargetAuras_UpdateDisplay()
end

function MainTargetAuras:Disable()
	local index

	if Main.API and Main.API.ResetUnitAuras then
		Main.API:ResetUnitAuras("target")
	end

	for index = 1, MAIN_TARGET_AURAS_MAX_BUTTONS do
		MainTargetAuras_SetButton(MainTargetAuras_GetButton(index), nil)
	end
	MainTargetAurasFrame:Hide()
end

Main.RegisterModule("target_auras", MainTargetAuras)

end
-- END TargetAuras.lua

-- BEGIN TargetDistance.lua
do
local MainTargetDistance = {
	name = "Target Distance",
	description = "Shows distance to your current target with local map math and server fallback.",
}

local MAIN_TARGET_DISTANCE_UPDATE_RATE = 1
local MAIN_TARGET_DISTANCE_FORMAT = "%d yds"
local MAIN_TARGET_DISTANCE_PENDING_TEXT = "-- yds"
local MAIN_TARGET_DISTANCE_CONTINENT_SPANS_YARDS = {
	Azeroth = { width = 57 * 533.333333, height = 38 * 533.333333 },
	Kalimdor = { width = 63 * 533.333333, height = 42 * 533.333333 },
}

local function MainTargetDistance_SetText(distanceYards)
	if distanceYards then
		MainTargetDistanceText:SetText(format(MAIN_TARGET_DISTANCE_FORMAT, distanceYards))
	else
		MainTargetDistanceText:SetText("")
	end
end

local function MainTargetDistance_UpdateAnchor()
	if not MainTargetDistanceFrame or not TargetPortrait then
		return
	end

	MainTargetDistanceFrame:ClearAllPoints()
	if TargetName and TargetName.IsVisible and TargetName:IsVisible() and TargetName.GetText and TargetName:GetText() and TargetName:GetText() ~= "" then
		MainTargetDistanceFrame:SetPoint("BOTTOM", "TargetPortrait", "TOP", 0, 16)
	else
		MainTargetDistanceFrame:SetPoint("BOTTOM", "TargetPortrait", "TOP", 0, 4)
	end
end

local function MainTargetDistance_GetMapSpan(mapFileName)
	if not mapFileName then
		return nil, nil
	end

	if string.find(mapFileName, "Azeroth") then
		return MAIN_TARGET_DISTANCE_CONTINENT_SPANS_YARDS.Azeroth.width, MAIN_TARGET_DISTANCE_CONTINENT_SPANS_YARDS.Azeroth.height
	end

	if string.find(mapFileName, "Kalimdor") then
		return MAIN_TARGET_DISTANCE_CONTINENT_SPANS_YARDS.Kalimdor.width, MAIN_TARGET_DISTANCE_CONTINENT_SPANS_YARDS.Kalimdor.height
	end

	return nil, nil
end

local function MainTargetDistance_RestoreMapSelection(continent, zone)
	if not continent then
		return
	end

	if continent == 0 then
		SetMapZoom(0)
	elseif zone and zone > 0 then
		SetMapZoom(continent, zone)
	else
		SetMapZoom(continent)
	end
end

local function MainTargetDistance_SelectContinent(continent)
	local playerX
	local playerY

	if not continent or continent <= 0 then
		return nil
	end

	SetMapZoom(continent)
	playerX, playerY = GetPlayerMapPosition("player")
	if playerX == 0 and playerY == 0 then
		return nil
	end

	return continent, GetMapInfo()
end

local function MainTargetDistance_GetLocalDistanceYards()
	local originalContinent
	local originalZone
	local selectedContinent
	local mapFileName
	local spanX
	local spanY
	local playerX
	local playerY
	local targetX
	local targetY
	local deltaX
	local deltaY

	originalContinent = GetCurrentMapContinent()
	if GetCurrentMapZone then
		originalZone = GetCurrentMapZone()
	else
		originalZone = 0
	end

	-- Target distance should not permanently change the world map selection while probing continents.
	selectedContinent, mapFileName = MainTargetDistance_SelectContinent(originalContinent)
	if not selectedContinent then
		selectedContinent, mapFileName = MainTargetDistance_SelectContinent(1)
	end
	if not selectedContinent then
		selectedContinent, mapFileName = MainTargetDistance_SelectContinent(2)
	end

	if not selectedContinent then
		MainTargetDistance_RestoreMapSelection(originalContinent, originalZone)
		return nil
	end

	spanX, spanY = MainTargetDistance_GetMapSpan(mapFileName)
	playerX, playerY = GetPlayerMapPosition("player")
	targetX, targetY = GetPlayerMapPosition("target")

	MainTargetDistance_RestoreMapSelection(originalContinent, originalZone)

	if not spanX or not spanY then
		return nil
	end
	if not playerX or not playerY or not targetX or not targetY then
		return nil
	end
	if (playerX == 0 and playerY == 0) or (targetX == 0 and targetY == 0) then
		return nil
	end

	deltaX = (targetX - playerX) * spanX
	deltaY = (targetY - playerY) * spanY
	return floor(math.sqrt((deltaX * deltaX) + (deltaY * deltaY)) + 0.5)
end

local function MainTargetDistance_UpdateDisplay()
	local distanceYards

	if not Main.IsModuleEnabled("target_distance") then
		MainTargetDistanceFrame:Hide()
		return
	end

	if not TargetFrame or not TargetFrame:IsVisible() or not UnitExists("target") then
		MainTargetDistance_SetText(nil)
		MainTargetDistanceFrame:Hide()
		return
	end

	MainTargetDistance_UpdateAnchor()
	MainTargetDistanceFrame:Show()
	distanceYards = MainTargetDistance_GetLocalDistanceYards()
	if distanceYards then
		MainTargetDistance_SetText(distanceYards)
		return
	end

	distanceYards = Main.API and Main.API.GetTargetDistanceYards and Main.API:GetTargetDistanceYards() or nil
	if distanceYards then
		MainTargetDistance_SetText(distanceYards)
		return
	end

	if Main.API then
		Main.API:RequestTargetDistance()
	end

	if Main.API and Main.API:IsTargetDistanceUnavailable() then
		MainTargetDistance_SetText(nil)
	else
		MainTargetDistanceText:SetText(MAIN_TARGET_DISTANCE_PENDING_TEXT)
	end
end

function MainTargetDistanceFrame_OnLoad()
	this.elapsed = 0
	this:RegisterEvent("PLAYER_ENTERING_WORLD")
	this:RegisterEvent("PLAYER_TARGET_CHANGED")
	MainTargetDistance_SetText(nil)
	this:Hide()
end

function MainTargetDistanceFrame_OnEvent(event)
	if event == "PLAYER_ENTERING_WORLD" or event == "PLAYER_TARGET_CHANGED" then
		if Main.API then
			Main.API:ResetTargetDistance()
		end
		this.elapsed = MAIN_TARGET_DISTANCE_UPDATE_RATE
		MainTargetDistance_UpdateDisplay()
	end
end

function MainTargetDistanceFrame_OnUpdate(elapsed)
	if not UnitExists or not UnitExists("target") then
		MainTargetDistance_SetText(nil)
		MainTargetDistanceFrame:Hide()
		return
	end

	this.elapsed = this.elapsed + elapsed
	if this.elapsed < MAIN_TARGET_DISTANCE_UPDATE_RATE then
		return
	end

	this.elapsed = 0
	MainTargetDistance_UpdateDisplay()
end

function MainTargetDistance:Init()
	MainTargetDistanceFrame:Hide()
end

function MainTargetDistance:Enable()
	if Main.API then
		Main.API:ResetTargetDistance()
	end
	MainTargetDistance_UpdateDisplay()
end

function MainTargetDistance:Disable()
	if Main.API then
		Main.API:ResetTargetDistance()
	end
	MainTargetDistance_SetText(nil)
	MainTargetDistanceFrame:Hide()
end

function MainTargetDistance:OnUILayoutChanged()
	if not Main.IsModuleEnabled("target_distance") then
		return
	end

	MainTargetDistance_UpdateDisplay()
end

Main.RegisterModule("target_distance", MainTargetDistance)

end
-- END TargetDistance.lua

-- BEGIN TutorialExtend.lua
do
local MainTutorialExtend = {
	name = "Tutorial Extend",
	description = "Shows the stock tutorial prompts again for brand new characters.",
}

local MAIN_TUTORIAL_EXTEND_MAX_PLAYED_SECONDS = 60
local MAIN_TUTORIAL_EXTEND_TUTORIAL_COUNT = 18

local function MainTutorialExtend_IsEligible()
	return UnitXP("player") == 0
end

local function MainTutorialExtend_InitializeTutorials()
	local tutorialIndex

	if not MainTutorialExtend_IsEligible() or MainTutorialExtend.initializedThisSession then
		return
	end

	for tutorialIndex = 1, MAIN_TUTORIAL_EXTEND_TUTORIAL_COUNT do
		TutorialFrame_NewTutorial(tutorialIndex)
	end

	MainTutorialExtend.initializedThisSession = 1

	-- The stock API only flashes the question mark button. Open the first tutorial automatically
	-- so new characters actually see the re-queued help prompts.
	if TutorialFrame and TutorialFrameQuestionMarkButton and not TutorialFrame:IsVisible() then
		ShowUIPanel(TutorialFrame)
		UIFrameFlashRemoveFrame(TutorialFrameQuestionMarkButton)
		TutorialFrameQuestionMarkButton:Hide()
	end
end

local function MainTutorialExtend_RequestTimePlayed()
	if MainTutorialExtend.requestPending then
		return
	end

	MainTutorialExtend.requestPending = 1
	RequestTimePlayed()
end

local function MainTutorialExtend_UpdateRegistration()
	if not MainTutorialExtendFrame then
		return
	end

	MainTutorialExtendFrame:UnregisterEvent("PLAYER_ENTERING_WORLD")
	MainTutorialExtendFrame:UnregisterEvent("TIME_PLAYED_MSG")

	if not Main.IsModuleEnabled("tutorial_extend") then
		return
	end

	if not MainTutorialExtend_IsEligible() then
		return
	end

	MainTutorialExtendFrame:RegisterEvent("PLAYER_ENTERING_WORLD")
	MainTutorialExtendFrame:RegisterEvent("TIME_PLAYED_MSG")
end

function MainTutorialExtendFrame_OnLoad()
	MainTutorialExtend_UpdateRegistration()
end

function MainTutorialExtendFrame_OnEvent(event)
	if not Main.IsModuleEnabled("tutorial_extend") then
		return
	end

	if event == "PLAYER_ENTERING_WORLD" then
		MainTutorialExtend.initializedThisSession = nil
		MainTutorialExtend_RequestTimePlayed()
	elseif event == "TIME_PLAYED_MSG" then
		MainTutorialExtend.requestPending = nil
		if floor(arg1) < MAIN_TUTORIAL_EXTEND_MAX_PLAYED_SECONDS then
			MainTutorialExtend_InitializeTutorials()
		end
		MainTutorialExtend_UpdateRegistration()
	end
end

function MainTutorialExtend:Init()
	MainTutorialExtend_UpdateRegistration()
end

function MainTutorialExtend:Enable()
	MainTutorialExtend_UpdateRegistration()
	if MainTutorialExtend_IsEligible() then
		MainTutorialExtend_RequestTimePlayed()
	end
end

function MainTutorialExtend:Disable()
	MainTutorialExtend.requestPending = nil
	MainTutorialExtend.initializedThisSession = nil
	MainTutorialExtend_UpdateRegistration()
end

Main.RegisterModule("tutorial_extend", MainTutorialExtend)

end
-- END TutorialExtend.lua

-- BEGIN ExtendedStats.lua
do
local MainExtendedStats = {
	name = "Extended Stats",
	description = "Shows an expanded stats panel beside the character sheet.",
}

local MAIN_EXTENDED_STATS_WHITE = "|cFFFFFFFF"
local MAIN_EXTENDED_STATS_RESET = "|r"
local MAIN_EXTENDED_STATS_BASE_PROC_CHANCE = 0.03
local MAIN_EXTENDED_STATS_BASE_CRIT_CHANCE = 0.05
local MAIN_EXTENDED_STATS_BASE_MELEE_MISS_CHANCE = 0.05
local MAIN_EXTENDED_STATS_SPELL_SCHOOLS = {"Holy", "Fire", "Nature", "Frost", "Shadow", "Arcane"}
local MAIN_EXTENDED_STATS_RESISTANCE_NAMES = {"Holy", "Fire", "Nature", "Frost", "Shadow"}
local MAIN_EXTENDED_STATS_SKILL_CATEGORIES = {"class", "secondary", "spec", "racial", "proficiency"}
local MAIN_EXTENDED_STATS_CLASS_NAME_TO_TOKEN = {
	Warrior = "WARRIOR",
	Paladin = "PALADIN",
	Hunter = "HUNTER",
	Rogue = "ROGUE",
	Priest = "PRIEST",
	Shaman = "SHAMAN",
	Mage = "MAGE",
	Warlock = "WARLOCK",
	Druid = "DRUID",
}
local MAIN_EXTENDED_STATS_CLASS_BASE_DODGE = {
	DRUID = 0.9,
	MAGE = 3.2,
	PALADIN = 0.7,
	PRIEST = 3.0,
	SHAMAN = 1.7,
	WARLOCK = 2.0,
}
local MAIN_EXTENDED_STATS_CLASS_AGI_DODGE_SCALING = {
	DRUID = {4.6, 20.0},
	PALADIN = {4.6, 20.0},
	SHAMAN = {4.6, 20.0},
	MAGE = {12.9, 20.0},
	ROGUE = {1.1, 14.5},
	HUNTER = {1.8, 26.5},
	PRIEST = {11.0, 20.0},
	WARLOCK = {8.4, 20.0},
	WARRIOR = {3.9, 20.0},
}
local MAIN_EXTENDED_STATS_CLASS_STRENGTH_SCALING_CRIT = {
	DRUID = {4.6, 20.0},
	PALADIN = {4.6, 20.0},
	SHAMAN = {4.6, 20.0},
	MAGE = {12.9, 20.0},
	ROGUE = {2.2, 29.0},
	HUNTER = {1.8, 26.5},
	PRIEST = {11.0, 20.0},
	WARLOCK = {8.4, 20.0},
	WARRIOR = {7.8, 40.0},
}
local MAIN_EXTENDED_STATS_CLASS_MAGIC_SCHOOLS = {
	WARRIOR = {},
	ROGUE = {},
	MAGE = {"Fire", "Frost"},
	PRIEST = {"Holy", "Shadow"},
	PALADIN = {"Holy"},
	DRUID = {"Nature"},
	WARLOCK = {"Fire", "Shadow"},
	SHAMAN = {"Fire", "Frost", "Nature"},
}

local function MainExtendedStats_FormatStat(baseValue, modifier)
	local totalValue
	local sign
	local color

	totalValue = baseValue + modifier
	if modifier == 0 then
		return tostring(baseValue)
	end

	sign = modifier > 0 and "+" or ""
	color = modifier > 0 and "|cff20ff20" or "|cffff2020"
	return color .. totalValue .. " (" .. baseValue .. sign .. modifier .. ")" .. "|r"
end

local function MainExtendedStats_Interpolate(level1Value, level60Value, level)
	return ((level1Value * (60 - level)) + (level60Value * (level - 1))) / 59
end

local function MainExtendedStats_EstimateArmorReduction(armor, level)
	local reduction

	reduction = (0.3 * (armor - 1)) / (10 * level + 89)
	if reduction > 0.75 then
		reduction = 0.75
	end
	if reduction < 0 then
		reduction = 0
	end
	return string.format("%.2f%%", reduction * 100)
end

local function MainExtendedStats_EstimateDodge(agility, level, classToken, defenseSkill)
	local baseValue
	local scaling
	local rate
	local bonus
	local difference
	local percent

	baseValue = MAIN_EXTENDED_STATS_CLASS_BASE_DODGE[classToken] or 0
	scaling = MAIN_EXTENDED_STATS_CLASS_AGI_DODGE_SCALING[classToken] or {20, 20}
	rate = MainExtendedStats_Interpolate(scaling[1], scaling[2], level)
	bonus = agility / rate
	difference = defenseSkill - (level * 5)
	percent = bonus + baseValue + difference * 0.04
	if percent > 100 then
		percent = 100
	end
	return string.format("%.2f%%", percent)
end

local function MainExtendedStats_EstimateBlock(strength, level, classToken, rating)
	local scaling
	local rate
	local bonus
	local difference
	local percent

	scaling = MAIN_EXTENDED_STATS_CLASS_AGI_DODGE_SCALING[classToken] or {20, 20}
	rate = MainExtendedStats_Interpolate(scaling[1], scaling[2], level)
	bonus = strength / rate
	difference = rating - (level * 5)
	percent = bonus + difference * 0.04
	if percent > 100 then
		percent = 100
	end
	if percent < 0 then
		percent = 0
	end
	return string.format("%.2f%%", percent)
end

local function MainExtendedStats_EstimateParry(defenseSkill, level)
	return string.format("%.2f%%", 5.0 + (defenseSkill - level * 5) * 0.04)
end

local function MainExtendedStats_EstimateProcChance(agility, level, classToken)
	local scaling
	local rate
	local procChance

	scaling = MAIN_EXTENDED_STATS_CLASS_AGI_DODGE_SCALING[classToken] or {20, 20}
	rate = MainExtendedStats_Interpolate(scaling[1], scaling[2], level)
	procChance = MAIN_EXTENDED_STATS_BASE_PROC_CHANCE + (agility / rate / 100)
	if procChance > 1 then
		procChance = 1
	end
	return string.format("%.2f%%", procChance * 100)
end

local function MainExtendedStats_EstimateBlockValue(strength)
	return tostring(strength)
end

local function MainExtendedStats_EstimateCritChance(strength, level, classToken, weaponSkill)
	local scaling
	local rate
	local baseChance
	local difference
	local bonus
	local critChance

	scaling = MAIN_EXTENDED_STATS_CLASS_STRENGTH_SCALING_CRIT[classToken] or {20, 20}
	rate = MainExtendedStats_Interpolate(scaling[1], scaling[2], level)
	baseChance = MAIN_EXTENDED_STATS_BASE_CRIT_CHANCE + (strength / rate / 100)
	difference = weaponSkill - (level * 5)
	if difference < 0 then
		bonus = difference * 0.002
	else
		bonus = difference * 0.0004
	end
	critChance = baseChance + bonus
	if critChance > 1 then
		critChance = 1
	end
	if critChance < 0 then
		critChance = 0
	end
	return string.format("%.2f%%", critChance * 100)
end

local function MainExtendedStats_EstimateMissChance(level, weaponSkill)
	local difference
	local missChance

	difference = (level * 5) - weaponSkill
	missChance = MAIN_EXTENDED_STATS_BASE_MELEE_MISS_CHANCE + difference * 0.04
	if missChance > 1 then
		missChance = 1
	end
	if missChance < 0 then
		missChance = 0
	end
	return string.format("%.2f%%", missChance * 100)
end

local function MainExtendedStats_EstimateHitChance()
	return "0.00%"
end

local function MainExtendedStats_EstimateSpellCritChance()
	return "5.00%"
end

local function MainExtendedStats_IsSchoolUsedByClass(classToken, schoolName)
	local schools
	local index

	schools = MAIN_EXTENDED_STATS_CLASS_MAGIC_SCHOOLS[classToken] or {}
	for index = 1, Main_ArrayCount(schools) do
		if schools[index] == schoolName then
			return 1
		end
	end
	return nil
end

local function MainExtendedStats_ClassUsesAnyMagic(classToken)
	local schools

	schools = MAIN_EXTENDED_STATS_CLASS_MAGIC_SCHOOLS[classToken]
	return schools and Main_ArrayCount(schools) > 0
end

local function MainExtendedStats_GetSkillRankByName(skillName)
	local counts
	local categoryIndex
	local category
	local count
	local index
	local name
	local rank

	counts = {GetSkillLineInfo()}
	for categoryIndex = 1, Main_ArrayCount(MAIN_EXTENDED_STATS_SKILL_CATEGORIES) do
		category = MAIN_EXTENDED_STATS_SKILL_CATEGORIES[categoryIndex]
		count = counts[categoryIndex] or 0
		for index = 1, count do
			name, _, rank = GetSkillByIndex(category, index)
			if name == skillName then
				return rank
			end
		end
	end

	return nil
end

local function MainExtendedStats_GetSpellSchoolSkill(schoolName)
	local counts
	local categoryIndex
	local category
	local count
	local index
	local name
	local rank

	counts = {GetSkillLineInfo()}
	for categoryIndex = 1, Main_ArrayCount(MAIN_EXTENDED_STATS_SKILL_CATEGORIES) do
		category = MAIN_EXTENDED_STATS_SKILL_CATEGORIES[categoryIndex]
		count = counts[categoryIndex] or 0
		for index = 1, count do
			name, _, rank = GetSkillByIndex(category, index)
			if name and strfind(string.lower(name), string.lower(schoolName)) then
				return rank
			end
		end
	end

	return nil
end

local function MainExtendedStats_EstimateSpellResistChanceBySchool(level, classToken)
	local result
	local defense
	local index
	local school
	local skill
	local difference
	local resistChance

	result = {}
	defense = level * 5
	for index = 1, Main_ArrayCount(MAIN_EXTENDED_STATS_SPELL_SCHOOLS) do
		school = MAIN_EXTENDED_STATS_SPELL_SCHOOLS[index]
		if not MAIN_EXTENDED_STATS_CLASS_MAGIC_SCHOOLS[classToken] or
			MainExtendedStats_IsSchoolUsedByClass(classToken, school) then
			skill = MainExtendedStats_GetSpellSchoolSkill(school) or 0
			difference = defense - skill
			resistChance = 0.04
			if difference > 0 then
				if difference < 75 then
					resistChance = resistChance + (difference / 5 / 100)
				else
					resistChance = resistChance + (0.04 + ((difference / 5 / 100 - 0.02) * 7))
				end
			end
			result[school] = string.format("%.2f%%", math.min(100, math.max(0, resistChance * 100)))
		else
			result[school] = "N/A"
		end
	end
	return result
end

local function MainExtendedStats_EstimateSpellDamage()
	return {
		Holy = "0",
		Fire = "0",
		Nature = "0",
		Frost = "0",
		Shadow = "0",
		Arcane = "0",
	}
end

local function MainExtendedStats_EstimateCastingSpeed()
	return "0.00%"
end

local function MainExtendedStats_EstimateSpellCostModifier()
	return "0.00%"
end

local function MainExtendedStats_EstimateManaRegen(spirit, classToken)
	local regen

	regen = 0
	if classToken == "PRIEST" then
		regen = spirit * 0.15
	elseif classToken == "MAGE" then
		regen = spirit * 0.1
	elseif classToken == "DRUID" then
		regen = spirit * 0.08
	elseif classToken == "PALADIN" then
		regen = spirit * 0.075
	elseif classToken == "SHAMAN" or classToken == "WARLOCK" then
		regen = spirit * 0.07
	end

	return string.format("%.2f", regen * 2.5) .. " / 5s"
end

local function MainExtendedStats_GetRangedWeaponStats()
	local name
	local minDamage
	local maxDamage
	local speed
	local weaponType
	local lineIndex
	local leftText
	local rightText
	local text
	local low
	local high
	local speedValue

	-- The classic API does not expose full ranged tooltip stats directly, so this parses the tooltip text.
	GameTooltip:SetOwner(UIParent, "ANCHOR_NONE")
	GameTooltip:SetInventoryItem("player", 18)

	for lineIndex = 1, 15 do
		leftText = getglobal("GameTooltipTextLeft" .. lineIndex)
		rightText = getglobal("GameTooltipTextRight" .. lineIndex)

		if lineIndex == 1 and leftText and leftText:GetText() then
			name = leftText:GetText()
		end

		if leftText and leftText:GetText() then
			text = leftText:GetText()
			_, _, low, high = strfind(text, "(%d+)%s?%-+%s?(%d+)%s?[Dd]amage")
			if low and high then
				minDamage = tonumber(low)
				maxDamage = tonumber(high)
			end
		end

		if rightText and rightText:GetText() then
			text = rightText:GetText()
			if text == "Bow" or text == "Gun" or text == "Thrown" or text == "Crossbow" or text == "Wand" then
				weaponType = text
			end
			if strfind(text, "Speed") then
				speedValue = strsub(text, strfind(text, "Speed") + 5)
				speedValue = gsub(speedValue, "[:%s]", "")
				speed = tonumber(speedValue) or speed
			end
		end
	end

	GameTooltip:Hide()
	return minDamage, maxDamage, speed, weaponType, name
end

local function MainExtendedStats_HasRangedWeaponEquipped()
	local lineIndex
	local leftText
	local text

	GameTooltip:SetOwner(UIParent, "ANCHOR_NONE")
	GameTooltip:SetInventoryItem("player", 18)

	for lineIndex = 1, 10 do
		leftText = getglobal("GameTooltipTextLeft" .. lineIndex)
		if leftText and leftText:GetText() then
			text = leftText:GetText()
			if strfind(text, "%d+%s?%-+%s?%d+%s?[Dd]amage") then
				GameTooltip:Hide()
				return 1
			end
		end
	end

	GameTooltip:Hide()
	return nil
end

local function MainExtendedStats_GetRangedWeaponSkill(weaponType)
	local skillName

	if weaponType == "Bow" then
		skillName = "Bows"
	elseif weaponType == "Gun" then
		skillName = "Guns"
	elseif weaponType == "Crossbow" then
		skillName = "Crossbows"
	elseif weaponType == "Thrown" then
		skillName = "Thrown"
	elseif weaponType == "Wand" then
		skillName = "Wands"
	end

	if not skillName then
		return nil
	end

	return MainExtendedStats_GetSkillRankByName(skillName)
end

local function MainExtendedStats_Update()
	local className
	local classToken
	local level
	local health
	local mana
	local strengthBase
	local strengthModifier
	local agilityBase
	local agilityModifier
	local staminaBase
	local staminaModifier
	local intellectBase
	local intellectModifier
	local spiritBase
	local spiritModifier
	local strengthTotal
	local agilityTotal
	local intellectTotal
	local spiritTotal
	local baseArmor
	local positiveArmor
	local negativeArmor
	local armorText
	local armorReductionText
	local defenseBase
	local defenseModifier
	local defenseText
	local defenseSkill
	local shieldSkill
	local blockSkill
	local blockRatingSkill
	local showBlockSkillText
	local attackBase
	local attackModifier
	local attackText
	local minDamage
	local maxDamage
	local damageBonus
	local rawBonus1
	local rawBonus2
	local rawBonus3
	local rawBonus4
	local rawBonus5
	local totalDamageBonus
	local damageText
	local mainHandSpeed
	local speedText
	local dodgeText
	local parryText
	local blockText
	local procText
	local blockValueText
	local critText
	local hitBonusText
	local missText
	local spellCritText
	local spellResistText
	local spellDamage
	local castingSpeedText
	local spellCostModifierText
	local manaRegenText
	local resistanceLines
	local resistanceIndex
	local resistanceBase
	local text
	local tooltipMinDamage
	local tooltipMaxDamage
	local rangedWeaponSpeed
	local rangedWeaponType
	local hasRangedWeapon
	local rangedColor
	local rangedAttackPower
	local rangedBonusDamage
	local finalMinDamage
	local finalMaxDamage
	local rangedSkill
	local rangedCritText
	local rangedMissText
	local rangedHitText
	local schoolIndex
	local schoolName
	local schoolValue
	local schoolColor

	if not MainExtendedStatsText then
		return
	end

	className = UnitClass("player")
	classToken = MAIN_EXTENDED_STATS_CLASS_NAME_TO_TOKEN[className] or "WARRIOR"
	level = UnitLevel("player") or 0
	health = UnitHealthMax("player") or 0
	mana = UnitManaMax("player") or 0

	strengthBase, strengthModifier = UnitStat("player", 1)
	agilityBase, agilityModifier = UnitStat("player", 2)
	staminaBase, staminaModifier = UnitStat("player", 3)
	intellectBase, intellectModifier = UnitStat("player", 4)
	spiritBase, spiritModifier = UnitStat("player", 5)

	strengthTotal = strengthBase + strengthModifier
	agilityTotal = agilityBase + agilityModifier
	intellectTotal = intellectBase + intellectModifier
	spiritTotal = spiritBase + spiritModifier

	_, baseArmor, positiveArmor, negativeArmor = UnitArmor("player")
	armorText = MainExtendedStats_FormatStat(baseArmor, positiveArmor + negativeArmor)
	armorReductionText = MainExtendedStats_EstimateArmorReduction(baseArmor + positiveArmor + negativeArmor, level)

	defenseBase, defenseModifier = UnitDefense("player")
	defenseText = MainExtendedStats_FormatStat(defenseBase, defenseModifier)
	defenseSkill = defenseBase + defenseModifier

	shieldSkill = MainExtendedStats_GetSkillRankByName("Shields") or (level * 5)
	blockSkill = MainExtendedStats_GetSkillRankByName("Block") or (level * 5)
	blockRatingSkill = defenseSkill
	showBlockSkillText = 1

	if classToken == "PALADIN" then
		blockRatingSkill = blockSkill
	elseif classToken == "WARRIOR" then
		blockRatingSkill = shieldSkill
	elseif classToken == "ROGUE" or classToken == "SHAMAN" or classToken == "HUNTER" then
		showBlockSkillText = nil
	end

	attackBase, attackModifier = UnitAttackBothHands("player")
	attackText = MainExtendedStats_FormatStat(attackBase, attackModifier)
	minDamage, maxDamage, damageBonus, rawBonus1, rawBonus2, rawBonus3, rawBonus4, rawBonus5 = UnitDamage("player")
	totalDamageBonus = damageBonus + rawBonus1 + rawBonus2 + rawBonus3 + rawBonus4 + rawBonus5
	damageText = string.format("%d - %d", minDamage + totalDamageBonus, maxDamage + totalDamageBonus)
	mainHandSpeed = UnitAttackSpeed("player")
	speedText = string.format("%.2f", mainHandSpeed or 0)

	dodgeText = MainExtendedStats_EstimateDodge(agilityTotal, level, classToken, defenseSkill)
	parryText = MainExtendedStats_EstimateParry(defenseSkill, level)
	blockText = MainExtendedStats_EstimateBlock(strengthTotal, level, classToken, blockRatingSkill)
	procText = MainExtendedStats_EstimateProcChance(agilityTotal, level, classToken)
	blockValueText = MainExtendedStats_EstimateBlockValue(strengthTotal)
	critText = MainExtendedStats_EstimateCritChance(strengthTotal, level, classToken, attackBase)
	hitBonusText = MainExtendedStats_EstimateHitChance()
	missText = MainExtendedStats_EstimateMissChance(level, attackBase)

	spellCritText = MainExtendedStats_EstimateSpellCritChance()
	spellResistText = MainExtendedStats_EstimateSpellResistChanceBySchool(level, classToken)
	spellDamage = MainExtendedStats_EstimateSpellDamage()
	castingSpeedText = MainExtendedStats_EstimateCastingSpeed()
	spellCostModifierText = MainExtendedStats_EstimateSpellCostModifier()
	manaRegenText = MainExtendedStats_EstimateManaRegen(spiritTotal, classToken)

	resistanceLines = {}
	for resistanceIndex = 1, 5 do
		_, resistanceBase = UnitResistance("player", resistanceIndex)
		table.insert(resistanceLines, string.format("%s: %d", MAIN_EXTENDED_STATS_RESISTANCE_NAMES[resistanceIndex], resistanceBase))
	end

	tooltipMinDamage, tooltipMaxDamage, rangedWeaponSpeed, rangedWeaponType = MainExtendedStats_GetRangedWeaponStats()
	hasRangedWeapon = MainExtendedStats_HasRangedWeaponEquipped()
	rangedColor = hasRangedWeapon and "" or "|cff888888"
	rangedAttackPower = agilityTotal * 2
	rangedBonusDamage = rangedAttackPower / 14
	finalMinDamage = tooltipMinDamage and (tooltipMinDamage + rangedBonusDamage) or rangedBonusDamage
	finalMaxDamage = tooltipMaxDamage and (tooltipMaxDamage + rangedBonusDamage) or rangedBonusDamage
	rangedSkill = MainExtendedStats_GetRangedWeaponSkill(rangedWeaponType) or (level * 5)
	rangedCritText = MainExtendedStats_EstimateCritChance(strengthTotal, level, classToken, rangedSkill)
	rangedMissText = MainExtendedStats_EstimateMissChance(level, rangedSkill)
	rangedHitText = MainExtendedStats_EstimateHitChance()

	text = ""
	text = text .. "HP: " .. health .. "\n"
	text = text .. "MP: " .. mana .. "\n\n"

	text = text .. MAIN_EXTENDED_STATS_WHITE .. "MELEE:\n" .. MAIN_EXTENDED_STATS_RESET
	text = text .. "Attack Rating: " .. attackText .. "\n"
	text = text .. "Damage: " .. damageText .. "\n"
	text = text .. "Attack Speed: " .. speedText .. "\n"
	text = text .. "Crit Chance: " .. critText .. "\n"
	text = text .. "Hit Chance (Bonus): " .. hitBonusText .. "\n"
	text = text .. "Miss Chance: " .. missText .. "\n"
	text = text .. "Proc Chance: " .. procText .. "\n\n"

	text = text .. MAIN_EXTENDED_STATS_WHITE .. "RANGED:\n" .. MAIN_EXTENDED_STATS_RESET
	text = text .. rangedColor .. "Attack Rating: " .. rangedSkill .. MAIN_EXTENDED_STATS_RESET .. "\n"
	if tooltipMinDamage then
		text = text .. rangedColor .. string.format("Damage: %.1f - %.1f\n", finalMinDamage, finalMaxDamage) .. MAIN_EXTENDED_STATS_RESET
	else
		text = text .. rangedColor .. "Damage: N/A" .. MAIN_EXTENDED_STATS_RESET .. "\n"
	end
	if rangedWeaponSpeed then
		text = text .. rangedColor .. string.format("Attack Speed: %.2f\n", rangedWeaponSpeed) .. MAIN_EXTENDED_STATS_RESET
	else
		text = text .. rangedColor .. "Attack Speed: N/A" .. MAIN_EXTENDED_STATS_RESET .. "\n"
	end
	text = text .. rangedColor .. "Crit Chance: " .. rangedCritText .. MAIN_EXTENDED_STATS_RESET .. "\n"
	text = text .. rangedColor .. "Hit Chance (Bonus): " .. rangedHitText .. MAIN_EXTENDED_STATS_RESET .. "\n"
	text = text .. rangedColor .. "Miss Chance: " .. rangedMissText .. MAIN_EXTENDED_STATS_RESET .. "\n\n"

	text = text .. MAIN_EXTENDED_STATS_WHITE .. "DEFENSIVE:\n" .. MAIN_EXTENDED_STATS_RESET
	text = text .. "Armor: " .. armorText .. "\n"
	text = text .. "Armor Dmg Reduction: " .. armorReductionText .. "\n"
	text = text .. "Defense: " .. defenseText .. "\n"
	if showBlockSkillText then
		if classToken == "PALADIN" then
			text = text .. "Block Skill: " .. blockRatingSkill .. "\n"
		else
			text = text .. "Shield Skill: " .. blockRatingSkill .. "\n"
		end
	end
	text = text .. "Dodge: " .. dodgeText .. "\n"
	text = text .. "Parry: " .. parryText .. "\n"
	text = text .. "Block: " .. blockText .. "\n"
	text = text .. "Block Value: " .. blockValueText .. "\n\n"

	if MainExtendedStats_ClassUsesAnyMagic(classToken) then
		rangedColor = ""
	else
		rangedColor = "|cff888888"
	end
	text = text .. MAIN_EXTENDED_STATS_WHITE .. "MAGICAL:\n" .. MAIN_EXTENDED_STATS_RESET
	text = text .. rangedColor .. "Spell Crit Chance: " .. spellCritText .. MAIN_EXTENDED_STATS_RESET .. "\n"
	text = text .. rangedColor .. "Casting Speed: " .. castingSpeedText .. MAIN_EXTENDED_STATS_RESET .. "\n"
	text = text .. rangedColor .. "Mana Regen: " .. manaRegenText .. MAIN_EXTENDED_STATS_RESET .. "\n"
	text = text .. rangedColor .. "Spell Cost Modifier: " .. spellCostModifierText .. MAIN_EXTENDED_STATS_RESET .. "\n\n"

	text = text .. MAIN_EXTENDED_STATS_WHITE .. "SPELL RESIST CHANCE:\n" .. MAIN_EXTENDED_STATS_RESET
	for schoolIndex = 1, Main_ArrayCount(MAIN_EXTENDED_STATS_SPELL_SCHOOLS) do
		schoolName = MAIN_EXTENDED_STATS_SPELL_SCHOOLS[schoolIndex]
		schoolValue = spellResistText[schoolName]
		if MainExtendedStats_IsSchoolUsedByClass(classToken, schoolName) then
			schoolColor = ""
		else
			schoolColor = "|cff888888"
		end
		text = text .. schoolColor .. schoolName .. " Resist Chance: " .. (schoolValue or "N/A") .. MAIN_EXTENDED_STATS_RESET .. "\n"
	end

	text = text .. "\n" .. MAIN_EXTENDED_STATS_WHITE .. "SPELL BONUS DAMAGE:\n" .. MAIN_EXTENDED_STATS_RESET
	for schoolIndex = 1, Main_ArrayCount(MAIN_EXTENDED_STATS_SPELL_SCHOOLS) do
		schoolName = MAIN_EXTENDED_STATS_SPELL_SCHOOLS[schoolIndex]
		schoolValue = spellDamage[schoolName]
		if MainExtendedStats_IsSchoolUsedByClass(classToken, schoolName) then
			schoolColor = ""
		else
			schoolColor = "|cff888888"
		end
		text = text .. schoolColor .. schoolName .. " Damage: " .. (schoolValue or "N/A") .. MAIN_EXTENDED_STATS_RESET .. "\n"
	end

	text = text .. "\n" .. MAIN_EXTENDED_STATS_WHITE .. "RESISTANCES:\n" .. MAIN_EXTENDED_STATS_RESET
	text = text .. table.concat(resistanceLines, "\n")

	MainExtendedStatsText:SetText(text)
end

function MainExtendedStatsFrame_OnLoad()
	this:RegisterEvent("PLAYER_ENTERING_WORLD")
	this:RegisterEvent("UNIT_STATS")
	this:RegisterEvent("UNIT_INVENTORY_CHANGED")
	this:RegisterEvent("UNIT_DEFENSE")
	this:Hide()
end

function MainExtendedStatsFrame_OnShow()
	if Main.IsModuleEnabled("extended_stats") then
		MainExtendedStats_Update()
	end
end

function MainExtendedStatsFrame_OnEvent(event)
	if not Main.IsModuleEnabled("extended_stats") then
		return
	end

	if event == "PLAYER_ENTERING_WORLD" then
		MainExtendedStats_Update()
	elseif (event == "UNIT_STATS" or event == "UNIT_INVENTORY_CHANGED" or event == "UNIT_DEFENSE") and arg1 == "player" then
		MainExtendedStats_Update()
	end
end

function MainExtendedStats:Init()
	MainExtendedStatsFrame:Hide()
end

function MainExtendedStats:Enable()
	MainExtendedStats_Update()
	MainExtendedStatsFrame:Show()
end

function MainExtendedStats:Disable()
	MainExtendedStatsFrame:Hide()
end

Main.RegisterModule("extended_stats", MainExtendedStats)

end
-- END ExtendedStats.lua

